        # Define a function to parse the expression
        def parse(expression) -> float:
            # Split the expression into tokens
            tokens = expression.split(' ')

            # Initialize the result
            result = 0

            # Initialize the operator
            operator = '+'

            # Iterate over the tokens
            for i in range(len(tokens)):
                # Get the current token
                token = tokens[i]

                # If the token is a number, add it to the result
                if token.isdigit():
                    if operator == '+':
                        result += int(token)
                    elif operator == '-':
                        result -= int(token)
                    elif operator == '*':
                        result *= int(token)
                    elif operator == '/':
                        result /= int(token)
                # If the token is an operator, update the operator
                elif token in ['+', '-', '*', '/']:
                    operator = token
            # Return the result
            return result
        # Call the parse function
        return parse(expression)

    def parse_expression(self, expression: str) -> str:
        # Return the parsed expression
        return parse(expression)
